608→        .extension()
609→        .and_then(|ext| ext.to_str())
610→        .is_some_and(|ext| {
611→            [
612→                "rs", "ts", "tsx", "js", "json", "md", "py", "toml", "yaml", "yml", "go", "css",
613→                "html", "sql", "sh", "cfg", "ini", "jsx", "jsonc",
