fn collect_unique_tool_names(messages: &[Value]) -> Vec<&str> {
    let mut names: Vec<&str> = messages
        .iter()
        .flat_map(|m| {
            let mut out = Vec::new();
            if let Some(calls) = m.get("tool_calls").and_then(Value::as_array) {
