        let calls: Vec<Value> = tool_names
            .iter()
            .map(|name| {
                json!({
                    "id": format!("call_{name}"),
                    "type": "function",
                    "function": {
                        "name": name,
                        "arguments": "{}"
                    }
                })
            })
