        json!({
            "role": "assistant",
            "content": text
        })
    }

    fn make_assistant_with_tools(text: &str, tool_names: &[&str]) -> Value {
        let calls: Vec<Value> = tool_names
            .iter()
            .map(|name| {
                json!({
                    "id": format!("call_{name}"),
                    "type": "function",
                    "function": {
                        "name": name,
                        "arguments": "{}"
                    }
                })
            })
            .collect();
        json!({
            "role": "assistant",
            "content": text,
            "tool_calls": calls
        })
    }

    fn make_tool_result(tool_name: &str, content: &str, success: bool) -> Value {
        json!({
            "role": "tool_result",
            "tool_name": tool_name,
            "content": content,
            "success": success
        })
    }

